const rows = $input.all().map(i => i.json);
const ETAPAS = ['BACKLOG', 'ANÁLISE', 'DESENVOLVIMENTO', 'TESTES', 'HOMOLOGAÇÃO', 'PRODUÇÃO', 'CONCLUÍDO'];
const map = {};
for (const row of rows) {
  const pid = String(row.projeto_id);
  if (!map[pid]) {
    map[pid] = {
      projeto_id: Number(row.projeto_id),
      projeto: row.projeto,
      etapas: Object.fromEntries(ETAPAS.map(e => [e, 0]))
    };
  }
  const statusKey = ETAPAS.find(e => e === row.status) ?? row.status;
  if (map[pid].etapas[statusKey] !== undefined) {
    map[pid].etapas[statusKey] = Number(row.total);
  }
}
return [{ json: { success: true, data: Object.values(map) } }];
